# Reporting Blueprint\nfrom flask import Blueprint, request, send_file\nfrom flask_jwt_extended import jwt_required\nfrom flask_app.models import db, StokMutasi, StokRealTime, OpnameSession, Produk, Outlet\nfrom flask_app.utils.auth import role_required\nfrom flask_app.utils.helpers import ResponseHelper\nfrom datetime import datetime, date\nfrom sqlalchemy import func, and_\nimport openpyxl\nfrom openpyxl.styles import Font, PatternFill, Alignment\nfrom io import BytesIO\nimport logging\n\nreport_bp = Blueprint('report', __name__)\nlogger = logging.getLogger(__name__)\n\n@report_bp.route('/stok-summary', methods=['GET'])\n@jwt_required()\ndef get_stok_summary_report():\n    \"\"\"Get stock summary report\"\"\"\n    try:\n        outlet_id = request.args.get('outlet_id', type=int)\n        tanggal_laporan = request.args.get('tanggal_laporan', default=str(date.today()))\n        \n        if not outlet_id:\n            return ResponseHelper.error('outlet_id required', status_code=400)\n        \n        # Get all products with stok\n        stok_items = db.session.query(\n            Produk.kode_barang,\n            Produk.nama_barang,\n            Produk.min_stok,\n            Produk.max_stok,\n            Produk.harga_beli,\n            Produk.harga_jual,\n            StokRealTime.qty_stok\n        ).join(\n            StokRealTime,\n            and_(\n                StokRealTime.produk_id == Produk.id,\n                StokRealTime.outlet_id == outlet_id\n            )\n        ).order_by(Produk.nama_barang).all()\n        \n        total_item = len(stok_items)\n        total_qty = sum([item[6] for item in stok_items])\n        total_nilai = sum([item[6] * float(item[4]) for item in stok_items])\n        \n        item_minimum = sum([1 for item in stok_items if item[6] <= item[2]])\n        item_overstock = sum([1 for item in stok_items if item[6] >= item[3]])\n        \n        data = [{\n            'kode_barang': item[0],\n            'nama_barang': item[1],\n            'min_stok': item[2],\n            'max_stok': item[3],\n            'qty_stok': item[6],\n            'harga_beli': float(item[4]),\n            'nilai_stok': item[6] * float(item[4]),\n            'status': 'minimum' if item[6] <= item[2] else ('overstock' if item[6] >= item[3] else 'aman')\n        } for item in stok_items]\n        \n        return ResponseHelper.success({\n            'tanggal_laporan': tanggal_laporan,\n            'outlet_id': outlet_id,\n            'summary': {\n                'total_item': total_item,\n                'total_qty': total_qty,\n                'total_nilai_stok': round(total_nilai, 2),\n                'item_minimum': item_minimum,\n                'item_overstock': item_overstock,\n                'item_aman': total_item - item_minimum - item_overstock\n            },\n            'items': data\n        })\n    \n    except Exception as e:\n        logger.error(f'Get stok summary report error: {str(e)}')\n        return ResponseHelper.error(str(e), status_code=500)\n\n@report_bp.route('/transaksi', methods=['GET'])\n@jwt_required()\ndef get_transaksi_report():\n    \"\"\"Get transaction report\"\"\"\n    try:\n        outlet_id = request.args.get('outlet_id', type=int)\n        start_date = request.args.get('start_date')\n        end_date = request.args.get('end_date', default=str(date.today()))\n        \n        if not outlet_id or not start_date:\n            return ResponseHelper.error('outlet_id and start_date required', status_code=400)\n        \n        query = StokMutasi.query.filter(\n            and_(\n                StokMutasi.outlet_id == outlet_id,\n                StokMutasi.tanggal_mutasi >= start_date,\n                StokMutasi.tanggal_mutasi <= end_date\n            )\n        ).order_by(StokMutasi.tanggal_mutasi.desc())\n        \n        transactions = query.all()\n        \n        data = [{\n            'tanggal': t.tanggal_mutasi.isoformat(),\n            'kode_barang': t.produk.kode_barang,\n            'nama_barang': t.produk.nama_barang,\n            'tipe_mutasi': str(t.tipe_mutasi.value),\n            'qty': t.qty,\n            'user': t.user.nama_lengkap if t.user else 'System',\n            'keterangan': t.keterangan\n        } for t in transactions]\n        \n        return ResponseHelper.success({\n            'start_date': start_date,\n            'end_date': end_date,\n            'total_records': len(transactions),\n            'transactions': data\n        })\n    \n    except Exception as e:\n        logger.error(f'Get transaksi report error: {str(e)}')\n        return ResponseHelper.error(str(e), status_code=500)\n\n@report_bp.route('/opname', methods=['GET'])\n@jwt_required()\ndef get_opname_report():\n    \"\"\"Get opname report\"\"\"\n    try:\n        session_id = request.args.get('session_id', type=int)\n        \n        if not session_id:\n            return ResponseHelper.error('session_id required', status_code=400)\n        \n        session = OpnameSession.query.get(session_id)\n        if not session:\n            return ResponseHelper.error('Opname session not found', status_code=404)\n        \n        details = session.detail\n        \n        data = [{\n            'produk': d.produk_rel.nama_barang,\n            'kode_barang': d.produk_rel.kode_barang,\n            'stok_sistem': d.stok_sistem,\n            'stok_fisik': d.stok_fisik_input,\n            'selisih': d.selisih,\n            'arah_selisih': d.arah_selisih,\n            'catatan': d.catatan_selisih\n        } for d in details]\n        \n        return ResponseHelper.success({\n            'session_id': session.id,\n            'tanggal_opname': session.tanggal_opname.isoformat(),\n            'status': str(session.status.value),\n            'total_item': session.total_item_checked,\n            'item_dengan_selisih': session.total_item_selisih,\n            'total_qty_selisih': session.total_qty_selisih,\n            'details': data\n        })\n    \n    except Exception as e:\n        logger.error(f'Get opname report error: {str(e)}')\n        return ResponseHelper.error(str(e), status_code=500)\n\n@report_bp.route('/export-excel/stok', methods=['GET'])\n@jwt_required()\n@role_required('admin', 'staff_gudang')\ndef export_stok_excel():\n    \"\"\"Export stok report to Excel\"\"\"\n    try:\n        outlet_id = request.args.get('outlet_id', type=int)\n        \n        if not outlet_id:\n            return ResponseHelper.error('outlet_id required', status_code=400)\n        \n        # Get data\n        stok_items = db.session.query(\n            Produk.kode_barang,\n            Produk.nama_barang,\n            Produk.min_stok,\n            Produk.max_stok,\n            Produk.harga_beli,\n            StokRealTime.qty_stok\n        ).join(\n            StokRealTime,\n            and_(\n                StokRealTime.produk_id == Produk.id,\n                StokRealTime.outlet_id == outlet_id\n            )\n        ).order_by(Produk.nama_barang).all()\n        \n        # Create Excel\n        wb = openpyxl.Workbook()\n        ws = wb.active\n        ws.title = \"Laporan Stok\"\n        \n        # Header\n        headers = ['Kode Barang', 'Nama Barang', 'Min Stok', 'Max Stok', 'Qty Stok', 'Harga Beli', 'Nilai Stok']\n        ws.append(headers)\n        \n        # Style header\n        header_fill = PatternFill(start_color='4472C4', end_color='4472C4', fill_type='solid')\n        header_font = Font(bold=True, color='FFFFFF')\n        \n        for cell in ws[1]:\n            cell.fill = header_fill\n            cell.font = header_font\n            cell.alignment = Alignment(horizontal='center')\n        \n        # Data rows\n        for item in stok_items:\n            nilai_stok = item[5] * float(item[4])\n            ws.append([\n                item[0],\n                item[1],\n                item[2],\n                item[3],\n                item[5],\n                float(item[4]),\n                nilai_stok\n            ])\n        \n        # Save to BytesIO\n        excel_file = BytesIO()\n        wb.save(excel_file)\n        excel_file.seek(0)\n        \n        logger.info(f'Stok report exported to Excel')\n        \n        return send_file(\n            excel_file,\n            as_attachment=True,\n            download_name=f'laporan_stok_{date.today()}.xlsx',\n            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'\n        )\n    \n    except Exception as e:\n        logger.error(f'Export stok excel error: {str(e)}')\n        return ResponseHelper.error(str(e), status_code=500)\n"
